const payload = $json;
const timestamp = new Date().toISOString();
const dateStr = new Date().toLocaleString('es-CO');

let output = `
в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—
в•‘     NEXUSRECOVER вҖ” AUTHORITIES NOTIFICATION                    в•‘
в•‘                 IRROPS Decision Support System                  в•‘
в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ

вҸ° Timestamp: ${dateStr}
ID: ${payload.scenario_id || 'unknown'}

в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
DISRUPTION CONTEXT
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ

рҹӣ« Hub Airport:           ${payload.disruption?.hub_airport || 'YYZ'}
рҹ“Қ Location:             ${payload.disruption?.hub_airport_name || 'Toronto Pearson International'}
вҡ пёҸ  Event:                ${payload.disruption?.event || 'Unknown'}

рҹ“Ҡ Capacity Impact:
   вҖў Nominal capacity:    ${payload.disruption?.runway_capacity_nominal_arr_per_hr || 12} arr/hr
   вҖў Storm capacity:      ${payload.disruption?.runway_capacity_storm_arr_per_hr || 4} arr/hr
   вҖў Reduction:          ${payload.disruption?.capacity_reduction_pct || 67}%

вңҲпёҸ  Flights affected:
   вҖў Inbound with delays: ${payload.disruption?.affected_inbound_flights || 0}/${payload.disruption?.total_inbound_flights || 0}
   вҖў Total outbound:     ${payload.disruption?.total_outbound_flights || 0}

в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
OPTIMIZER SUMMARY
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ

рҹ’° Costs:
   вҖў Baseline (no action):      $${(payload.optimizer_summary?.baseline_cost_usd || 0).toLocaleString('en-US')}
   вҖў Optimized (with plan):     $${(payload.optimizer_summary?.optimized_cost_usd || 0).toLocaleString('en-US')}
   вң“ Savings:                   $${(payload.optimizer_summary?.savings_usd || 0).toLocaleString('en-US')} (${payload.optimizer_summary?.savings_pct || 0}%)

рҹ‘Ҙ Passenger Impact:
   вҖў Total PAX groups:          ${payload.optimizer_summary?.total_pax_groups || 0}
   вң“ Protected (connected):     ${payload.optimizer_summary?.pax_groups_protected || 0}
   вң— Stranded (rebooking):      ${payload.optimizer_summary?.pax_groups_stranded || 0}

вңҲпёҸ  Flight Actions:
   вҖў Holds applied:             ${payload.optimizer_summary?.flights_held || 0}
   вҖў Diversions ordered:        ${payload.optimizer_summary?.flights_diverted || 0}
   вҖў Total delay applied:       ${payload.optimizer_summary?.total_delay_minutes_applied || 0} minutes

в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
DIVERSION ORDERS (${(payload.diversion_orders || []).length})
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
`;

if (payload.diversion_orders && payload.diversion_orders.length > 0) {
  for (let i = 0; i < payload.diversion_orders.length; i++) {
    const div = payload.diversion_orders[i];
    output += `
в”Ңв”Җ DIVERSION ${i + 1} в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ
в”Ӯ
в”Ӯ  Flight:              ${div.flight_id}
в”Ӯ  From:                ${payload.disruption?.hub_airport || 'YYZ'} (${payload.disruption?.hub_airport_name || 'Toronto Pearson'})
в”Ӯ  To:                  ${div.to_airport} (${div.to_airport_name})
в”Ӯ  Urgency:             ${div.urgency || 'IMMEDIATE'}
в”Ӯ  ETA at alternate:    ${div.eta_at_alternate}
в”Ӯ  
в”Ӯ  Passengers:
в”Ӯ    вҖў Total onboard:   ${div.total_pax_onboard}
в”Ӯ    вҖў Business class:  ${div.pax_breakdown?.business || 0}
в”Ӯ    вҖў Economy class:   ${div.pax_breakdown?.economy || 0}
в”Ӯ  
в”Ӯ  Ground Operations Required:
`;
    if (div.ground_ops_required) {
      for (const op of div.ground_ops_required) {
        output += `в”Ӯ    вң“ ${op}\n`;
      }
    }
    output += `в”Ӯ  
в”Ӯ  Contacts to Notify:
`;
    if (div.contacts_to_notify) {
      for (const contact of div.contacts_to_notify) {
        output += `в”Ӯ    вҶ’ ${contact}\n`;
      }
    }
    output += `в”Ӯ
в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ
`;
  }
} else {
  output += `\n  (No diversions ordered)\n`;
}

output += `
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
DEPARTURE HOLD ORDERS (${(payload.hold_orders || []).length})
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
`;

if (payload.hold_orders && payload.hold_orders.length > 0) {
  for (let i = 0; i < payload.hold_orders.length; i++) {
    const hold = payload.hold_orders[i];
    output += `
в”Ңв”Җ HOLD ${i + 1} в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ
в”Ӯ
в”Ӯ  Flight:                  ${hold.flight_id}
в”Ӯ  Destination:             ${hold.destination}
в”Ӯ  Status:                  ${hold.action}
в”Ӯ  Urgency:                 ${hold.urgency}
в”Ӯ  
в”Ӯ  Timing:
в”Ӯ    вҖў Original ETD:        ${hold.original_etd}
в”Ӯ    вҖў Revised ETD:         ${hold.revised_etd}
в”Ӯ    вҖў Hold duration:       +${hold.hold_duration_min} minutes
в”Ӯ  
в”Ӯ  Impact:
в”Ӯ    вҖў Connecting PAX protected: ${hold.connecting_pax_protected}
в”Ӯ    вҖў Hold cost:           $${(hold.hold_cost_usd || 0).toLocaleString('en-US')}
в”Ӯ  
в”Ӯ  Gate Actions:
`;
    if (hold.gate_actions) {
      for (const action of hold.gate_actions) {
        output += `в”Ӯ    вң“ ${action}\n`;
      }
    }
    output += `в”Ӯ
в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ
`;
  }
} else {
  output += `\n  (No holds ordered)\n`;
}

output += `
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
ALTERNATE AIRPORTS STATUS (${(payload.alternate_airports_activated || []).length})
в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ
`;

if (payload.alternate_airports_activated && payload.alternate_airports_activated.length > 0) {
  for (const alt of payload.alternate_airports_activated) {
    output += `
рҹӣ¬  ${alt.iata} вҖ” ${alt.name}
    Status: ${alt.status}
    Incoming flights: ${(alt.incoming_flights || []).join(', ') || 'None'}
    Total PAX: ${alt.total_pax_incoming}
    Slots: ${alt.slots_used}/${alt.available_slots} used
    Transfer time to YYZ: ${alt.transfer_time_to_yyz_min} min
`;
  }
} else {
  output += `\n  (No alternates activated)\n`;
}

output += `
в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—
в•‘ End of Authorities Notification                                в•‘
в•‘ Generated by: ${payload.issued_by || 'NexusRecover'}${' '.repeat(33 - (payload.issued_by || 'NexusRecover').length)}в•‘
в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ
`;

return { formattedText: output };
